; struct region {
;	double A[4];     // 32 bytes. last element is ignored.
; }
OFFSETOF_REGION_A   EQU 32*(0)
SIZEOF_REGION EQU 32*(1)
REGION_COUNT  EQU 1

REGIONS SEGMENT ALIGN(32)  ; AVX-256 (i.e. 32-byte) alignment
  regions LABEL qword
; L
; R
; m
  Outer	dq 0.0, 0.0, 0.0, 0.0
; Inner
REGIONS ENDS

GLOBAL_NODE SEGMENT ALIGN(32)
global_node LABEL qword
S   dq 1.0
F   dq 0.0
kT  dq 0.10000000000000001
Je0 dq 0.0
GLOBAL_NODE ENDS

; struct edge {
; }
SIZEOF_EDGE  EQU 32*(0)
EDGE_COUNT EQU 1652

EDGES SEGMENT ALIGN(32)
; edges  ; (0 bytes) array of empty edge structs
EDGES ENDS

; struct edge_region {
;	double J, Je1, Jee, b;  // 32 bytes. unused fields are ignored.
; }
OFFSETOF_REGION_J   EQU 32*(0) + 8*(0)
SIZEOF_EDGE_REGION  EQU 32*(1)
EDGE_REGION_COUNT EQU 5

EDGE_REGIONS SEGMENT ALIGN(32)
  edge_regions LABEL qword
; L_None
  L_L	dq 1.0, 0.0, 0.0, 0.0
; L_R
  L_m	dq 1.0, 0.0, 0.0, 0.0
; L_Outer
; L_Inner
; None_L
; R_None
; R_L
  R_R	dq 1.0, 0.0, 0.0, 0.0
; R_m
; R_Outer
; R_Inner
; None_R
; m_None
; m_L
  m_R	dq -1.0, 0.0, 0.0, 0.0
  m_m	dq 1.0, 0.0, 0.0, 0.0
; m_Outer
; m_Inner
; None_m
; Outer_None
; Outer_L
; Outer_R
; Outer_m
; Outer_Outer
; Outer_Inner
; None_Outer
; Inner_None
; Inner_L
; Inner_R
; Inner_m
; Inner_Outer
; Inner_Inner
; None_Inner
EDGE_REGIONS ENDS

GLOBAL_EDGE SEGMENT ALIGN(32)
; global_edge  ; (0 bytes) none defined
GLOBAL_EDGE ENDS

