.data?
PRNG SEGMENT ALIGN(32)
; Vectorized xoshiro256**
prng_state dq 4 dup (?, ?, ?, ?)  ; initialized at runtime
PRNG ENDS

.code
; @return ymm0: -\Delta U (Negated for Boltzmann distribution.)
; @param  ymm1: s'_i
; @param  ymm2: f'_i (unused)
;         ymm3: temp/scratch reg.
;         ymm4: s_i, m_i, then (unused)
;         ymm5: f_i, m'_i, then (unused)
;         ymm6: (unused), \Delta s_i, then \Delta m_i
;         ymm7: (unused), \Delta f_i, then (unused)
;         ymm8: s_j, f_j, or m_j
;         ymm9: temp/scratch reg.
deltaU_0_0_0 PROC  ; node[0]
	; skipping -deltaU_Je0
	; skipping -deltaU_Je1
	; skipping -deltaU_Jee
	; skipping -deltaU_b
	; skipping -deltaU_B
	; skipping -deltaU_D

	; Phase 1:
	vmovapd ymm4, ymmword ptr [nodes + (0)*SIZEOF_NODE + OFFSETOF_SPIN]  ; load s_i

	; Phase 2:
	vsubpd ymm6, ymm1, ymm4  ; \Delta s_i = s'_i - s_i
	; (ymm4) m_i = s_i since f_i = 0
	; (ymm1) m'_i = s'_i since f'_i = 0

	; -deltaU_A calculation
	vmulpd ymm9, ymm1, ymm1  ; m' Hadamard squared: m'2
	vfnmadd231pd ymm9, ymm4, ymm4  ; ymm9 -= ymm4 * ymm4 -> m'2 - m2
	_vdotp xmm0, ymm0, ymm9, ymmword ptr [Outer + OFFSETOF_REGION_A], xmm8  ; load A_Outer (region)

	; -deltaU_J calculation
	; [load group 1]
	; edge: 0_0_0 -> 1_0_0
	_vdotp xmm9, ymm9, ymm6, ymmword ptr [nodes + (1)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_1_0_0 (neighbor)
	; edge: 0_0_0 -> 0_1_0
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (3)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_0_1_0 (neighbor)
	; edge: 0_0_0 -> 0_0_1
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (30)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_0_0_1 (neighbor)
	vfmadd231sd xmm0, xmm9, qword ptr [L_L + OFFSETOF_REGION_J]  ; load J_L_L (region)

	; Phase 3: (skip)

	ret
deltaU_0_0_0 ENDP

deltaU_1_0_0 PROC  ; node[1]
	; skipping -deltaU_Je0
	; skipping -deltaU_Je1
	; skipping -deltaU_Jee
	; skipping -deltaU_b
	; skipping -deltaU_B
	; skipping -deltaU_D

	; Phase 1:
	vmovapd ymm4, ymmword ptr [nodes + (1)*SIZEOF_NODE + OFFSETOF_SPIN]  ; load s_i

	; Phase 2:
	vsubpd ymm6, ymm1, ymm4  ; \Delta s_i = s'_i - s_i
	; (ymm4) m_i = s_i since f_i = 0
	; (ymm1) m'_i = s'_i since f'_i = 0

	; -deltaU_A calculation
	vmulpd ymm9, ymm1, ymm1  ; m' Hadamard squared: m'2
	vfnmadd231pd ymm9, ymm4, ymm4  ; ymm9 -= ymm4 * ymm4 -> m'2 - m2
	_vdotp xmm0, ymm0, ymm9, ymmword ptr [Outer + OFFSETOF_REGION_A], xmm8  ; load A_Outer (region)

	; -deltaU_J calculation
	; [load group 1]
	; edge: 0_0_0 -> 1_0_0
	_vdotp xmm9, ymm9, ymm6, ymmword ptr [nodes + (0)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_0_0_0 (neighbor)
	; edge: 1_0_0 -> 2_0_0
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (2)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_2_0_0 (neighbor)
	; edge: 1_0_0 -> 1_1_0
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (4)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_1_1_0 (neighbor)
	; edge: 1_0_0 -> 1_0_1
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (31)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_1_0_1 (neighbor)
	vfmadd231sd xmm0, xmm9, qword ptr [L_L + OFFSETOF_REGION_J]  ; load J_L_L (region)

	; Phase 3: (skip)

	ret
deltaU_1_0_0 ENDP

deltaU_2_0_0 PROC  ; node[2]
	; skipping -deltaU_Je0
	; skipping -deltaU_Je1
	; skipping -deltaU_Jee
	; skipping -deltaU_b
	; skipping -deltaU_B
	; skipping -deltaU_D

	; Phase 1:
	vmovapd ymm4, ymmword ptr [nodes + (2)*SIZEOF_NODE + OFFSETOF_SPIN]  ; load s_i

	; Phase 2:
	vsubpd ymm6, ymm1, ymm4  ; \Delta s_i = s'_i - s_i
	; (ymm4) m_i = s_i since f_i = 0
	; (ymm1) m'_i = s'_i since f'_i = 0

	; -deltaU_A calculation
	; skip. For this node, A is not defined at any level (local, region, nor global).

	; -deltaU_J calculation
	; [load group 1]
	; edge: 1_0_0 -> 2_0_0
	_vdotp xmm9, ymm9, ymm6, ymmword ptr [nodes + (1)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_1_0_0 (neighbor)
	; edge: 2_0_0 -> 2_1_0
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (5)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_2_1_0 (neighbor)
	; edge: 2_0_0 -> 2_0_1
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (32)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_2_0_1 (neighbor)
	vmulsd xmm0, xmm9, qword ptr [L_L + OFFSETOF_REGION_J]  ; load J_L_L (region)
	; [load group 2]
	; edge: 2_0_0 -> 3_0_0
	_vdotp xmm9, ymm9, ymm6, ymmword ptr [nodes + (300)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_3_0_0 (neighbor)
	vfmadd231sd xmm0, xmm9, qword ptr [L_m + OFFSETOF_REGION_J]  ; load J_L_m (region)
	; [load group 3]
	; skip. For edge, J is not defined at any level (local, region, nor global).
	; skip parameter loading for the null load group

	; Phase 3: (skip)

	ret
deltaU_2_0_0 ENDP

deltaU_0_1_0 PROC  ; node[3]
	; skipping -deltaU_Je0
	; skipping -deltaU_Je1
