	vmulsd xmm0, xmm9, qword ptr [m_R + OFFSETOF_REGION_J]  ; load J_m_R (region)
	; [load group 3]
	; edge: 4_8_8 -> 4_8_9
	_vdotp xmm9, ymm9, ymm6, ymmword ptr [nodes + (600)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_4_8_8 (neighbor)
	; edge: 4_7_9 -> 4_8_9
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (627)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_4_7_9 (neighbor)
	; edge: 4_8_9 -> 5_8_9
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (631)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_5_8_9 (neighbor)
	; edge: 4_8_9 -> 4_9_9
	_vdotadd xmm9, ymm9, ymm6, ymmword ptr [nodes + (633)*SIZEOF_NODE + OFFSETOF_SPIN], xmm3  ; load s_4_9_9 (neighbor)
	vfmadd231sd xmm0, xmm9, qword ptr [R_R + OFFSETOF_REGION_J]  ; load J_R_R (region)

	; Phase 3: (skip)

	ret
deltaU_4_8_9 ENDP

